-- ─── HR/SF Agent Data (from "SF" sheet) ──────────────────────────────
DROP TABLE IF EXISTS agent_sf;
CREATE TABLE agent_sf (
  id               INT AUTO_INCREMENT PRIMARY KEY,
  employee_id      VARCHAR(20)  DEFAULT NULL,
  full_name        VARCHAR(200) DEFAULT NULL,
  prenom           VARCHAR(100) DEFAULT NULL,
  nom              VARCHAR(100) DEFAULT NULL,
  goscode          VARCHAR(50)  DEFAULT NULL,
  supervisor_prenom VARCHAR(100) DEFAULT NULL,
  supervisor_nom   VARCHAR(100) DEFAULT NULL,
  project_name     VARCHAR(200) DEFAULT NULL,
  facility         VARCHAR(150) DEFAULT NULL,
  hire_date        DATE         DEFAULT NULL,
  termination_date DATE         DEFAULT NULL,
  nbr_login        INT          DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

