-- ─── View: active_agents_full (joins SF + account status) ───────────
CREATE OR REPLACE VIEW active_agents_full AS
SELECT
  sf.employee_id,
  sf.full_name,
  sf.prenom,
  sf.nom,
  sf.goscode,
  CONCAT(sf.supervisor_prenom, ' ', sf.supervisor_nom) AS supervisor,
  sf.project_name,
  sf.facility,
  sf.hire_date,
  sf.termination_date,
  aa.samaccountname  AS windows_login,
  aa.etat_login,
  aa.last_login,
  aa.date_out        AS depart_date
FROM agent_sf sf
LEFT JOIN agent_accounts aa ON aa.employee_id = sf.employee_id
ORDER BY sf.project_name, sf.nom;

